// Extract JSON from Claude's response
const response = $input.first().json;

// Get text from content array
let text = '';
if (response.content && Array.isArray(response.content)) {
  text = response.content[0].text;
} else {
  throw new Error('No content in Claude response');
}

console.log('Raw Claude response length:', text.length);
console.log('First 300 chars:', text.substring(0, 300));

// Function to repair common JSON issues
function repairJSON(jsonStr) {
  // Remove any text before the first { or [
  const start = jsonStr.search(/[{\[]/);
  if (start > 0) {
    jsonStr = jsonStr.substring(start);
  }

  // Remove any text after the last } or ]
  const end = jsonStr.lastIndexOf('}') > jsonStr.lastIndexOf(']') 
    ? jsonStr.lastIndexOf('}') + 1 
    : jsonStr.lastIndexOf(']') + 1;
  if (end > 0) {
    jsonStr = jsonStr.substring(0, end);
  }

  return jsonStr;
}

// Try to parse the response
let courseData;
let jsonText = '';

try {
  // Check if response contains markdown code blocks
  const jsonMatch = text.match(/```(?:json)?\s*([\s\S]*?)```/);

  if (jsonMatch) {
    // Extract JSON from code block
    jsonText = jsonMatch[1].trim();
    console.log('Extracted JSON from code block, length:', jsonText.length);
  } else {
    // Try to parse directly
    jsonText = text.trim();
    console.log('Using raw text as JSON');
  }

  // Try to repair common JSON issues
  jsonText = repairJSON(jsonText);

  // Attempt to parse
  try {
    courseData = JSON.parse(jsonText);
    console.log('Successfully parsed JSON');
  } catch (parseError) {
    console.error('Initial parse failed:', parseError.message);

    // Log context around the error
    if (parseError.message.includes('position')) {
      const match = parseError.message.match(/position (\d+)/);
      if (match) {
        const pos = parseInt(match[1]);
        const start = Math.max(0, pos - 100);
        const end = Math.min(jsonText.length, pos + 100);
        console.error('\n=== Context around error position ===');
        console.error('Position:', pos);
        console.error('Context:', jsonText.substring(start, end));
        console.error('Character at position:', jsonText[pos]);
        console.error('=====================================\n');
      }
    }

    // Try one more time with more aggressive cleaning
    console.log('Attempting aggressive JSON repair...');
    let cleaned = jsonText
      .replace(/\\n/g, '\\\\n')  // Double escape newlines
      .replace(/([^\\])"([^":,\]}\s])/g, '$1\\"$2');  // Escape unescaped quotes

    try {
      courseData = JSON.parse(cleaned);
      console.log('Successfully parsed with aggressive repair');
    } catch (finalError) {
      // Save the problematic JSON to help debug
      console.error('\n=== FULL PROBLEMATIC JSON ===');
      console.error(jsonText);
      console.error('=============================\n');
      throw new Error(`JSON parsing failed after repair attempts: ${parseError.message}`);
    }
  }

  // Validate required fields
  if (!courseData.course || !courseData.course.title) {
    throw new Error('Missing course title');
  }

  if (!courseData.lessons || courseData.lessons.length === 0) {
    throw new Error('No lessons provided');
  }

  // Ensure all lessons have required fields
  courseData.lessons.forEach((lesson, index) => {
    if (!lesson.title) {
      throw new Error(`Lesson ${index} missing title`);
    }
    if (lesson.order === undefined) {
      lesson.order = index;
    }
    if (!lesson.content_markdown) {
      throw new Error(`Lesson ${index} missing content_markdown`);
    }
  });

  console.log('Successfully validated course data');
  console.log('Course:', courseData.course.title);
  console.log('Lessons:', courseData.lessons.length);

  return {
    json: courseData
  };

} catch (error) {
  throw new Error(`Failed to parse Claude response: ${error.message}\n\nCheck execution logs for full details.`);
}
